function formatJson(value: unknown): string {
  try {
    return JSON.stringify(value, null, 2);
  } catch {
    return String(value);
  }
}

function parseCsvList(raw: string): string[] {
  const parts = raw
    .split(',')
    .map((item) => item.trim())
    .filter((item) => item.length > 0);
  return Array.from(new Set(parts));
}

function isObjectRecord(value: unknown): value is Record<string, unknown> {
  return Boolean(value && typeof value === 'object' && !Array.isArray(value));
}

function readLaunchTemplateHealth(template: Record<string, unknown>): ModelLaunchTemplateHealth | null {
  if (!isObjectRecord(template.health)) return null;
  return template.health as ModelLaunchTemplateHealth;
}

function launchTemplateHealthVariant(
  health: ModelLaunchTemplateHealth | null
): 'default' | 'secondary' | 'destructive' | 'outline' {
  if (!health) return 'outline';
  if (Boolean(health.demoted)) return 'destructive';
  if (Boolean(health.unstable)) return 'secondary';
  const score = Number(health.health_score ?? 0);
  return score >= 80 ? 'outline' : 'secondary';
}

function formatLaunchTemplateHealthSummary(health: ModelLaunchTemplateHealth | null): string {
  if (!health) return 'no launch history';
  const score = Number(health.health_score ?? 0);
  const attempts = Number(health.attempt_count ?? 0);
  const failureRate = Math.round(Number(health.failure_rate ?? 0) * 100);
  const status = String(health.last_status ?? 'n/a');
  return `score ${score.toFixed(0)} • attempts ${attempts} • failure ${failureRate}% • last ${status}`;
}

function formatRecentLaunchOutcomes(health: ModelLaunchTemplateHealth | null): string {
  if (!health || !Array.isArray(health.recent_outcomes) || health.recent_outcomes.length === 0) {
    return '';
  }
  const parts = health.recent_outcomes
    .filter((item): item is Record<string, unknown> => isObjectRecord(item))
    .map((item) => {
      const status = String(item.status ?? 'unknown');
      const ready = Boolean(item.ready);
      return `${status}${ready ? '' : '(!ready)'}`;
    })
    .filter((item) => item.length > 0);
  return parts.join(' -> ');
}

function renderLaunchHistoryBarWidth(count: number, maxCount: number): string {
  const boundedMax = Math.max(1, maxCount);
  const ratio = Math.max(0, Math.min(1, count / boundedMax));
  return `${Math.max(8, Math.round(ratio * 100))}%`;
}

function formatLaunchTemplateSuppressionReason(reason: string): string {
  const clean = String(reason || '').trim().toLowerCase();
  if (!clean) return '';
  if (clean === 'retry_strategy_demoted') return 'suppressed: retry strategy demoted';
  if (clean === 'retry_strategy_unstable') return 'suppressed: retry strategy unstable';
  return `suppressed: ${clean.replace(/_/g, ' ')}`;
}

function formatLaunchTemplateBlacklistReason(reason: string): string {
  const clean = String(reason || '').trim().toLowerCase();
  if (!clean) return '';
  if (clean === 'persistent_failure_streak') return 'blacklisted: persistent failure streak';
  if (clean === 'long_horizon_failure_rate') return 'blacklisted: long-horizon failure rate';
  if (clean === 'demoted_recent_failure_pressure') return 'blacklisted: recent failure pressure';
  if (clean === 'strategy_and_template_demoted') return 'blacklisted: strategy and template demoted';
  return `blacklisted: ${clean.replace(/_/g, ' ')}`;
}

function formatRoutePolicyReason(reasonCode: string): string {
  const clean = String(reasonCode || '').trim().toLowerCase();
  if (!clean) return '';
  if (clean === 'local_launch_template_blacklisted') return 'local launcher blacklisted';
  if (clean === 'local_launch_template_demoted') return 'local launcher demoted';
  if (clean === 'local_launch_template_suppressed') return 'local launcher suppressed';
  if (clean === 'local_launch_template_unready') return 'local launcher not ready';
  if (clean === 'local_launch_review_required') return 'local route needs review';
  if (clean === 'launch_profile_unmatched') return 'launch profile unmatched';
  if (clean === 'route_policy_provider_error') return 'route policy provider error';
  if (clean === 'route_policy_blocked') return 'route blocked';
  if (clean === 'route_policy_gated') return 'route gated';
  return clean.replace(/_/g, ' ');
}

function formatVoiceRouteStatus(status: unknown): string {
  const clean = String(status ?? '').trim().toLowerCase();
  if (!clean) return 'unknown';
  if (clean === 'stable') return 'stable';
  if (clean === 'rerouted') return 'rerouted';
  if (clean === 'recovery') return 'recovery';
  if (clean === 'blocked') return 'blocked';
  if (clean === 'gated') return 'gated';
  return clean.replace(/_/g, ' ');
}

function formatLaunchTemplateStrategySummary(template: Record<string, unknown>, health: ModelLaunchTemplateHealth | null): string {
  const retryProfileHint = String(template.retry_profile_hint ?? health?.retry_profile_hint ?? '').trim();
  const retryStrategyScoreValue = template.retry_strategy_score ?? health?.retry_strategy_score;
  const retryStrategyScore =
    typeof retryStrategyScoreValue === 'number'
      ? retryStrategyScoreValue
      : Number.parseFloat(String(retryStrategyScoreValue ?? ''));
  const strategyHealth = isObjectRecord(template.retry_strategy_health)
    ? template.retry_strategy_health
    : isObjectRecord(health?.retry_strategy_health)
      ? health.retry_strategy_health
      : null;
  const statusLabel = strategyHealth
    ? Boolean(strategyHealth.demoted)
      ? 'demoted'
      : Boolean(strategyHealth.unstable)
        ? 'unstable'
        : 'healthy'
    : '';
  const parts: string[] = [];
  if (retryProfileHint) {
    parts.push(`retry ${retryProfileHint}`);
  }
  if (Number.isFinite(retryStrategyScore)) {
    parts.push(`score ${Math.round(retryStrategyScore)}`);
  }
  if (statusLabel) {
    parts.push(statusLabel);
  }
  return parts.join(' • ');
}

function formatLaunchTemplateAutonomySummary(template: Record<string, unknown>, health: ModelLaunchTemplateHealth | null): string {
  const autonomyPolicy = isObjectRecord(template.autonomy_policy)
    ? template.autonomy_policy
    : isObjectRecord(health?.autonomy_policy)
      ? health.autonomy_policy
      : null;
  const autonomousAllowed = Boolean(
    autonomyPolicy?.autonomous_allowed ?? template.autonomous_allowed ?? health?.autonomous_allowed
  );
  const autonomyScoreValue = autonomyPolicy?.autonomy_score ?? template.autonomy_score ?? health?.autonomy_score;
  const autonomyScore =
    typeof autonomyScoreValue === 'number' ? autonomyScoreValue : Number.parseFloat(String(autonomyScoreValue ?? ''));
  const cooldownHintValue = autonomyPolicy?.cooldown_hint_s ?? template.cooldown_hint_s ?? health?.cooldown_hint_s;
  const cooldownHint =
    typeof cooldownHintValue === 'number' ? cooldownHintValue : Number.parseInt(String(cooldownHintValue ?? ''), 10);
  const parts: string[] = [];
  parts.push(autonomousAllowed ? 'autonomy allowed' : 'autonomy gated');
  if (Number.isFinite(autonomyScore)) {
    parts.push(`auto-score ${Math.round(autonomyScore)}`);
  }
  if (Number.isFinite(cooldownHint) && cooldownHint > 0) {
    parts.push(`cooldown ${Math.round(cooldownHint / 60)}m`);
  }
  return parts.join(' • ');
}

function collectConnectorRemediationHints(
  preflight: ExternalConnectorPreflightResponse | null
): ConnectorRemediationHint[] {
  if (!preflight) return [];
  const rootHints = Array.isArray(preflight.remediation_hints) ? preflight.remediation_hints : [];
  if (rootHints.length > 0) return rootHints;
  const contract = isObjectRecord(preflight.contract_diagnostic) ? preflight.contract_diagnostic : {};
  const nested = Array.isArray(contract.remediation_hints) ? contract.remediation_hints : [];
  return nested;
}

function collectConnectorRemediationPlan(
  preflight: ExternalConnectorPreflightResponse | null
): ConnectorRemediationPhase[] {
  if (!preflight) return [];
  const rootPlan = Array.isArray(preflight.remediation_plan) ? preflight.remediation_plan : [];
  if (rootPlan.length > 0) return rootPlan;
  const contract = isObjectRecord(preflight.contract_diagnostic) ? preflight.contract_diagnostic : {};
  const nested = Array.isArray(contract.remediation_plan) ? contract.remediation_plan : [];
  return nested;
}

function pickConnectorArgsPatch(preflight: ExternalConnectorPreflightResponse | null): Record<string, unknown> {
  const hints = collectConnectorRemediationHints(preflight);
  for (const hint of hints) {
    if (!hint || typeof hint !== 'object') continue;
    const patch = isObjectRecord(hint.args_patch) ? hint.args_patch : null;
    if (patch && Object.keys(patch).length > 0) return patch;
  }
  const plan = collectConnectorRemediationPlan(preflight);
  for (const phase of plan) {
    if (!phase || typeof phase !== 'object') continue;
    const patch = isObjectRecord(phase.args_patch) ? phase.args_patch : null;
    if (patch && Object.keys(patch).length > 0) return patch;
  }
  return {};
}

function pickConnectorToolAction(preflight: ExternalConnectorPreflightResponse | null): ConnectorPreflightToolAction | null {
  const hints = collectConnectorRemediationHints(preflight);
  for (const hint of hints) {
    if (!hint || typeof hint !== 'object') continue;
    const toolAction = isObjectRecord(hint.tool_action) ? hint.tool_action : null;
    if (toolAction && typeof toolAction.action === 'string' && toolAction.action.trim()) {
      return {
        ...toolAction,
        action: String(toolAction.action).trim(),
      } as ConnectorPreflightToolAction;
    }
  }
  const plan = collectConnectorRemediationPlan(preflight);
  for (const phase of plan) {
    if (!phase || typeof phase !== 'object') continue;
    const toolAction = isObjectRecord(phase.tool_action) ? phase.tool_action : null;
    if (toolAction && typeof toolAction.action === 'string' && toolAction.action.trim()) {
      return {
        ...toolAction,
        action: String(toolAction.action).trim(),
      } as ConnectorPreflightToolAction;
    }
  }
  return null;
}

function buildConnectorRemediationExecutionQueue(
  preflight: ExternalConnectorPreflightResponse | null
): ConnectorRemediationExecutionStep[] {
  if (!preflight) return [];
  const plan = collectConnectorRemediationPlan(preflight);
  const hints = collectConnectorRemediationHints(preflight);
  const queue: ConnectorRemediationExecutionStep[] = [];
  const seen = new Set<string>();

  const pushStep = (
    step: Omit<ConnectorRemediationExecutionStep, 'step_id'> & { dedupe_key: string }
  ) => {
    const dedupeKey = step.dedupe_key.trim().toLowerCase();
    if (!dedupeKey || seen.has(dedupeKey)) return;
    seen.add(dedupeKey);
    queue.push({
      step_id: `remediation-step-${queue.length + 1}`,
      source: step.source,
      phase: step.phase,
      severity: step.severity,
      summary: step.summary,
      args_patch: step.args_patch,
      tool_action: step.tool_action,
      stop_on_error: step.stop_on_error,
    });
  };

  for (let index = 0; index < plan.length; index += 1) {
    const phase = plan[index];
    if (!phase || typeof phase !== 'object') continue;
    const phaseName = String(phase.phase ?? `phase-${index + 1}`).trim() || `phase-${index + 1}`;
    const summary = String(phase.summary ?? phase.status ?? phaseName).trim() || phaseName;
    const status = String(phase.status ?? '').trim().toLowerCase();
    const argsPatch = isObjectRecord(phase.args_patch) ? (phase.args_patch as Record<string, unknown>) : undefined;
    const toolAction = isObjectRecord(phase.tool_action) ? (phase.tool_action as ConnectorPreflightToolAction) : undefined;
    const severity = status === 'failed' ? 'high' : status === 'warning' ? 'medium' : 'low';
    if (argsPatch && Object.keys(argsPatch).length > 0) {
      pushStep({
        dedupe_key: `plan:${phaseName}:args:${JSON.stringify(argsPatch)}`,
        source: 'plan',
        phase: phaseName,
        severity,
        summary: `${summary} (apply args patch)`,
        args_patch: argsPatch,
        stop_on_error: false,
      });
    }
    if (toolAction && typeof toolAction.action === 'string' && toolAction.action.trim()) {
      pushStep({
        dedupe_key: `plan:${phaseName}:action:${String(toolAction.action).trim().toLowerCase()}`,
        source: 'plan',
        phase: phaseName,
        severity,
        summary: `${summary} (run ${String(toolAction.action).trim()})`,
        tool_action: {
          ...toolAction,
          action: String(toolAction.action).trim(),
        },
        stop_on_error: severity === 'high',
      });
    }
  }

  for (let index = 0; index < hints.length; index += 1) {
    const hint = hints[index];
    if (!hint || typeof hint !== 'object') continue;
    const code = String(hint.code ?? `hint-${index + 1}`).trim() || `hint-${index + 1}`;
    const severity = String(hint.severity ?? 'medium').trim().toLowerCase() || 'medium';
    const summary = String(hint.message ?? code).trim() || code;
    const argsPatch = isObjectRecord(hint.args_patch) ? (hint.args_patch as Record<string, unknown>) : undefined;
    const toolAction = isObjectRecord(hint.tool_action) ? (hint.tool_action as ConnectorPreflightToolAction) : undefined;
    if (argsPatch && Object.keys(argsPatch).length > 0) {
      pushStep({
        dedupe_key: `hint:${code}:args:${JSON.stringify(argsPatch)}`,
        source: 'hint',
        phase: code,
        severity,
        summary: `${summary} (apply args patch)`,
        args_patch: argsPatch,
        stop_on_error: false,
      });
    }
    if (toolAction && typeof toolAction.action === 'string' && toolAction.action.trim()) {
      pushStep({
        dedupe_key: `hint:${code}:action:${String(toolAction.action).trim().toLowerCase()}`,
        source: 'hint',
        phase: code,
        severity,
        summary: `${summary} (run ${String(toolAction.action).trim()})`,
        tool_action: {
          ...toolAction,
          action: String(toolAction.action).trim(),
        },
        stop_on_error: severity === 'high' || severity === 'critical',
      });
    }
  }
  return queue;
}

function extractMissionIdFromGoalPayload(payload: Record<string, unknown> | null): string {
  if (!payload || typeof payload !== 'object' || Array.isArray(payload)) return '';
  const direct = String(payload.mission_id ?? '').trim();
  if (direct) return direct;

  const request =
    payload.request && typeof payload.request === 'object' && !Array.isArray(payload.request)
      ? (payload.request as Record<string, unknown>)
      : {};
  const metadata =
    request.metadata && typeof request.metadata === 'object' && !Array.isArray(request.metadata)
      ? (request.metadata as Record<string, unknown>)
      : {};
  return String(metadata.__jarvis_mission_id ?? '').trim();
}

function scheduleVariant(status: string): 'default' | 'secondary' | 'outline' | 'destructive' {
  const normalized = status.toLowerCase();
  if (normalized === 'failed') return 'destructive';
  if (normalized === 'completed') return 'default';
  if (normalized === 'paused') return 'outline';
  if (normalized === 'cancelled') return 'outline';
  return 'secondary';
}

function runtimeHealthVariant(status: string, ready?: boolean): 'default' | 'secondary' | 'outline' | 'destructive' {
  const normalized = status.toLowerCase();
  if (normalized === 'blocked' || normalized === 'error' || normalized === 'failed') return 'destructive';
  if (normalized === 'degraded' || normalized === 'warning') return 'secondary';
  if (normalized === 'success' || normalized === 'ready' || ready === true) return 'outline';
  return 'secondary';
}

function humanizeRuntimeLabel(value: string): string {
  return value
    .split(/[_-]+/)
    .filter(Boolean)
    .map((item) => item.charAt(0).toUpperCase() + item.slice(1))
    .join(' ');
}

function canCancelSchedule(status: string): boolean {
  const normalized = status.toLowerCase();
  return !['completed', 'failed', 'cancelled'].includes(normalized);
}

function canPauseSchedule(status: string): boolean {
  const normalized = status.toLowerCase();
  return ['pending', 'retry_wait'].includes(normalized);
}

function canResumeSchedule(status: string): boolean {
  return status.toLowerCase() === 'paused';
}

function canRunNowSchedule(status: string): boolean {
  const normalized = status.toLowerCase();
  return !['cancelled', 'running', 'dispatched'].includes(normalized);
}

function triggerVariant(status: string): 'default' | 'secondary' | 'outline' | 'destructive' {
  const normalized = status.toLowerCase();
  if (normalized === 'cancelled') return 'destructive';
  if (normalized === 'paused') return 'outline';
  if (normalized === 'active') return 'default';
  return 'secondary';
}

function canPauseTrigger(status: string): boolean {
  return status.toLowerCase() === 'active';
}

function canResumeTrigger(status: string): boolean {
  return status.toLowerCase() === 'paused';
}

function canRunNowTrigger(status: string): boolean {
  return status.toLowerCase() !== 'cancelled';
}

function canCancelTrigger(status: string): boolean {
  return status.toLowerCase() !== 'cancelled';
}

function formatSecondsCompact(value: number): string {
  if (!Number.isFinite(value) || value <= 0) return 'off';
  if (value % 86400 === 0) return `${Math.floor(value / 86400)}d`;
  if (value % 3600 === 0) return `${Math.floor(value / 3600)}h`;
  if (value % 60 === 0) return `${Math.floor(value / 60)}m`;
  return `${Math.floor(value)}s`;
}

function formatEtaSeconds(value: number | null | undefined): string {
  if (typeof value !== 'number' || !Number.isFinite(value) || value < 0) return 'n/a';
  if (value < 1) return '<1s';
  if (value >= 86400) return `${Math.round(value / 86400)}d`;
  if (value >= 3600) return `${Math.round(value / 3600)}h`;
  if (value >= 60) return `${Math.round(value / 60)}m`;
  return `${Math.round(value)}s`;
}

function clampRuntimeBudget(value: number, fallback: number): number {
  const candidate = Number.isFinite(value) ? Math.trunc(value) : fallback;
  return Math.max(10, Math.min(3600, candidate || fallback));
}

function clampStepBudget(value: number, fallback: number): number {
  const candidate = Number.isFinite(value) ? Math.trunc(value) : fallback;
  return Math.max(1, Math.min(250, candidate || fallback));
}

function isTerminalGoalStatus(status: string): boolean {
  return ['completed', 'failed', 'blocked', 'cancelled'].includes(status.toLowerCase());
}

function isoToLocalInputValue(value: Date): string {
  const year = value.getFullYear();
  const month = String(value.getMonth() + 1).padStart(2, '0');
  const day = String(value.getDate()).padStart(2, '0');
  const hours = String(value.getHours()).padStart(2, '0');
  const minutes = String(value.getMinutes()).padStart(2, '0');
  return `${year}-${month}-${day}T${hours}:${minutes}`;
}

function formatIso(value: string | undefined): string {
  if (!value) return '';
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return value;
  return parsed.toLocaleString();
}

function formatRefreshStamp(value: unknown): string {
  if (!value) return 'never';
  if (!(value instanceof Date) && typeof value !== 'string' && typeof value !== 'number') return 'never';
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return 'never';
  return parsed.toLocaleTimeString();
}

function asObjectRecord(value: unknown): Record<string, unknown> {
  if (value && typeof value === 'object' && !Array.isArray(value)) {
    return value as Record<string, unknown>;
  }
  return {};
}

interface ModelSetupScopeDescriptor {
  manifestPath: string;
  workspaceRoot: string;
  scopeKey: string;
}

function normalizeModelSetupScopeValue(value: unknown): string {
  return String(value ?? '')
    .trim()
    .replace(/\\/g, '/');
}

function buildModelSetupScopeDescriptor(value: unknown): ModelSetupScopeDescriptor | null {
  const row = asObjectRecord(value);
  const manifestPath = normalizeModelSetupScopeValue(row.manifest_path ?? row.manifestPath ?? row.path);
  const workspaceRoot = normalizeModelSetupScopeValue(row.workspace_root ?? row.workspaceRoot);
  if (!manifestPath && !workspaceRoot) {
    return null;
  }
  const scopeKey = [workspaceRoot, manifestPath]
    .filter(Boolean)
    .map((item) => item.toLowerCase())
    .join('::');
  return {
    manifestPath,
    workspaceRoot,
    scopeKey,
  };
}

function pickModelSetupScope(...values: unknown[]): ModelSetupScopeDescriptor | null {
  for (const value of values) {
    const scope = buildModelSetupScopeDescriptor(value);
    if (scope) {
      return scope;
    }
  }
  return null;
}

function withModelSetupScope<T extends Record<string, unknown>>(
  input: T,
  scope?: ModelSetupScopeDescriptor | null
): T & Record<string, unknown> {
  if (!scope) {
    return input;
  }
  return {
    ...input,
    manifest_path: scope.manifestPath || undefined,
    workspace_root: scope.workspaceRoot || undefined,
  };
}

function formatModelSetupScopeLabel(scope?: ModelSetupScopeDescriptor | null): string {
  if (!scope) return '';
  const workspaceName = scope.workspaceRoot.split('/').filter(Boolean).pop() ?? scope.workspaceRoot;
  const manifestName = scope.manifestPath.split('/').filter(Boolean).pop() ?? scope.manifestPath;
  if (workspaceName && manifestName) {
    return `${workspaceName} :: ${manifestName}`;
  }
  return manifestName || workspaceName || scope.scopeKey;
}

function formatUnixTimestamp(value: unknown): string {
  const numeric = typeof value === 'number' ? value : Number(value);
  if (!Number.isFinite(numeric) || numeric <= 0) return '';
  return new Date(numeric * 1000).toLocaleString();
}

function parseCommaSeparatedList(value: string): string[] {
  return value
    .split(',')
    .map((item) => item.trim().toLowerCase())
    .filter(Boolean);
}

function pickTtsRecommendedProvider(
  ttsDiagnostics: TtsDiagnosticsResponse | null,
  voiceDiagnostics: VoiceDiagnosticsResponse | null
): string {
  const direct = String(ttsDiagnostics?.recommended_provider ?? '').trim().toLowerCase();
  if (direct) return direct;
  const voiceTts = asObjectRecord(voiceDiagnostics?.tts);
  const nested = String(voiceTts.recommended_provider ?? '').trim().toLowerCase();
  if (nested) return nested;
  return 'auto';
}

function extractTtsPolicySnapshot(
  ttsDiagnostics: TtsDiagnosticsResponse | null,
  voiceDiagnostics: VoiceDiagnosticsResponse | null
): TtsPolicyStatusResponse | null {
  const direct = asObjectRecord(ttsDiagnostics?.policy);
  if (Object.keys(direct).length > 0 && typeof direct.status === 'string') {
    return direct as TtsPolicyStatusResponse;
  }
  const voiceTts = asObjectRecord(voiceDiagnostics?.tts);
  const nested = asObjectRecord(voiceTts.policy);
  if (Object.keys(nested).length > 0 && typeof nested.status === 'string') {
    return nested as TtsPolicyStatusResponse;
  }
  return null;
}

function extractSttPolicySnapshot(voiceDiagnostics: VoiceDiagnosticsResponse | null): SttPolicyStatusResponse | null {
  const direct = asObjectRecord(voiceDiagnostics?.stt_policy);
  if (Object.keys(direct).length > 0 && typeof direct.status === 'string') {
    return direct as SttPolicyStatusResponse;
  }
  return null;
}

function ttsProviderHealthLabel(
  diagnostics: TtsDiagnosticsResponse | null,
  provider: 'local' | 'elevenlabs'
): 'ready' | 'degraded' | 'unknown' {
  const providers = asObjectRecord(diagnostics?.providers);
  const row = asObjectRecord(providers[provider]);
  if (!Object.keys(row).length) return 'unknown';
  if (provider === 'local') {
    const localProviders = asObjectRecord(row.providers);
    const pyttsx3 = asObjectRecord(localProviders.pyttsx3);
    const ready = Boolean(pyttsx3.ready ?? true);
    return ready ? 'ready' : 'degraded';
  }
  const ready = Boolean(row.ready ?? false);
  const configured = Boolean(row.configured ?? false);
  if (ready && configured) return 'ready';
  if (!configured && !ready) return 'degraded';
  if (ready) return 'ready';
  return 'degraded';
}

function pickRunnableAction(actions: string[], toolMap: Record<string, ToolDefinition>): string {
  for (const action of actions) {
    if (toolMap[action]) return action;
  }
  return '';
}

function getErrorMessage(error: unknown): string {
  if (error instanceof Error) return error.message;
  if (typeof error === 'string') return error;
  return 'Unknown error';
}

function clamp01(value: unknown): number {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) return 0;
  return Math.max(0, Math.min(1, numeric));
}

function formatCompactDateTime(value: unknown): string {
  const raw = String(value ?? '').trim();
  if (!raw) return 'n/a';
  const date = new Date(raw);
  if (Number.isNaN(date.getTime())) return raw;
  return date.toLocaleString([], {
    month: 'short',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
  });
}

function parseJsonObject(raw: string): { ok: true; value: Record<string, unknown> } | { ok: false; error: string } {
  const text = raw.trim();
  if (!text) return { ok: true, value: {} };

  try {
    const parsed = JSON.parse(text) as unknown;
    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
      return { ok: false, error: 'Arguments must be a JSON object.' };
    }
    return { ok: true, value: parsed as Record<string, unknown> };
  } catch (error) {
    return { ok: false, error: `Invalid JSON: ${getErrorMessage(error)}` };
  }
}

function parseJsonObjectArray(
  raw: string
): { ok: true; value: Record<string, unknown>[] } | { ok: false; error: string } {
  const text = raw.trim();
  if (!text) return { ok: true, value: [] };

  try {
    const parsed = JSON.parse(text) as unknown;
    if (!Array.isArray(parsed)) {
      return { ok: false, error: 'Workflow steps must be a JSON array.' };
    }
    const rows: Record<string, unknown>[] = [];
    for (let index = 0; index < parsed.length; index += 1) {
      const item = parsed[index];
      if (!item || typeof item !== 'object' || Array.isArray(item)) {
        return { ok: false, error: `Workflow step #${index + 1} must be a JSON object.` };
      }
      rows.push(item as Record<string, unknown>);
    }
    return { ok: true, value: rows };
  } catch (error) {
    return { ok: false, error: `Invalid JSON: ${getErrorMessage(error)}` };
  }
}

function normalizeToolMap(raw: Record<string, unknown>): Record<string, ToolDefinition> {
  const output: Record<string, ToolDefinition> = {};
  for (const [action, value] of Object.entries(raw)) {
    if (!value || typeof value !== 'object' || Array.isArray(value)) continue;
    const candidate = value as Record<string, unknown>;
    const requiredArgsRaw = Array.isArray(candidate.required_args) ? candidate.required_args : [];
    const requiredArgs = requiredArgsRaw
      .map((item) => String(item ?? '').trim())
      .filter((item, index, all) => item.length > 0 && all.indexOf(item) === index);
    output[action] = {
      description: String(candidate.description ?? ''),
      risk: String(candidate.risk ?? 'unknown'),
      requires_confirmation: Boolean(candidate.requires_confirmation),
      required_args: requiredArgs,
    };
  }
  return output;
}

function missingRequiredArgsForAction(
  action: string,
  args: Record<string, unknown>,
  tools: Record<string, ToolDefinition>
): string[] {
  const def = tools[action];
  if (!def || !Array.isArray(def.required_args) || def.required_args.length === 0) return [];
  return def.required_args.filter((key) => !(key in args));
}

function riskVariant(risk: string): 'default' | 'secondary' | 'outline' | 'destructive' {
  const normalized = risk.toLowerCase();
  if (normalized === 'high') return 'destructive';
  if (normalized === 'medium') return 'secondary';
  if (normalized === 'low') return 'outline';
  return 'default';
}

function coerceApprovalRecord(value: unknown): ApprovalRecord | null {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null;
  const candidate = value as Partial<ApprovalRecord>;
  if (typeof candidate.approval_id !== 'string') return null;

  return {
    approval_id: candidate.approval_id,
    action: String(candidate.action ?? ''),
    source: String(candidate.source ?? ''),
    args_hash: String(candidate.args_hash ?? ''),
    args_preview:
      candidate.args_preview && typeof candidate.args_preview === 'object' && !Array.isArray(candidate.args_preview)
        ? (candidate.args_preview as Record<string, unknown>)
        : {},
    reason: String(candidate.reason ?? ''),
    status: String(candidate.status ?? 'pending'),
    created_at: String(candidate.created_at ?? ''),
    expires_at: String(candidate.expires_at ?? ''),
    approved_at: candidate.approved_at ?? null,
    consumed_at: candidate.consumed_at ?? null,
    note: typeof candidate.note === 'string' ? candidate.note : '',
    reuse_count: typeof candidate.reuse_count === 'number' ? candidate.reuse_count : 0,
    last_reused_at: typeof candidate.last_reused_at === 'string' ? candidate.last_reused_at : null,
    last_reuse_reason: typeof candidate.last_reuse_reason === 'string' ? candidate.last_reuse_reason : '',
  };
}

function extractApprovalFromResult(result: ActionExecutionResponse): ApprovalRecord | null {
  const output = result.output;
  if (!output || typeof output !== 'object' || Array.isArray(output)) return null;
  return coerceApprovalRecord((output as Record<string, unknown>).approval);
}

function extractApprovalFromDesktopResponse(result: DesktopInteractResponse): ApprovalRecord | null {
  return coerceApprovalRecord((result as Record<string, unknown>).approval);
}

