  const sortedActions = useMemo(() => Object.keys(tools).sort((a, b) => a.localeCompare(b)), [tools]);

  const filteredActions = useMemo(() => {
    const needle = filter.trim().toLowerCase();
    if (!needle) return sortedActions;
    return sortedActions.filter((action) => {
      const def = tools[action];
      return action.toLowerCase().includes(needle) || def.description.toLowerCase().includes(needle);
    });
  }, [filter, sortedActions, tools]);

