  const connectorRemediationRecommendedProfile = useMemo<ConnectorRemediationPolicyProfile>(() => {
    const backend = String(connectorBackendRecommendation?.profile ?? '').trim().toLowerCase();
    if (backend === 'strict' || backend === 'balanced' || backend === 'aggressive') {
      return backend;
    }
    const trend = String(connectorSimulationTrendsResult?.recommended_profile ?? '').trim().toLowerCase();
    if (trend === 'strict' || trend === 'balanced' || trend === 'aggressive') return trend;
    const analytics = connectorSimulationCompareAnalytics;
    if (!analytics) return 'balanced';
    if (analytics.errorDelta > 0.08 || analytics.readyDelta < -0.08 || analytics.scoreGap > 0.2) return 'strict';
    if (analytics.readyDelta >= 0.08 && analytics.errorDelta <= -0.06 && analytics.confidenceDelta >= 0.05) {
      return 'aggressive';
    }
    return 'balanced';
  }, [connectorBackendRecommendation, connectorSimulationCompareAnalytics, connectorSimulationTrendsResult]);
