    const routeBias = isObjectRecord(ttsPolicySnapshot.route_bias)
      ? (ttsPolicySnapshot.route_bias as Record<string, unknown>)
      : {};
    setVoiceTtsPolicyRouteBiasLocal(
      Math.max(-4, Math.min(4, Number(routeBias.local ?? 0) || 0))
    );
