        const summary = payload.summary && isObjectRecord(payload.summary) ? payload.summary : {};
        toast({
          title: 'Scheduler Replay Ready',
          description: `dispatches:${Number(summary.dispatch_count ?? 0)} • critical:${Number(summary.critical_dispatch_count ?? 0)}`,
        });
