                            {voiceSttPolicyLastUpdate ? (
                              <pre className="max-h-[100px] overflow-auto font-mono text-[10px] leading-relaxed text-primary/90">
                                {formatJson(voiceSttPolicyLastUpdate)}
                              </pre>
                            ) : null}
